#include <stdio.h>
#include <stdlib.h>
typedef struct Rectangle {
    int x1, y1, x2, y2;
} Rectangle;

int intersect(Rectangle *r1, Rectangle *r2) {
    if (r1->x2 < r2->x1 || r2->x2 < r1->x1 || r1->y2 < r2->y1 || r2->y2 < r1->y1)
        return 0;
    return 1;
}

int main() {
    int Q;
    scanf("%d", &Q);
    Rectangle *rectangles = (Rectangle *)malloc(Q * sizeof(Rectangle));
    int count = 0;
    for (int i = 0; i < Q; i++) {
        char op;
        scanf(" %c", &op);
        if (op == 'I') {
            scanf("%d %d %d %d", &rectangles[count].x1, &rectangles[count].y1, &rectangles[count].x2, &rectangles[count].y2);
            count++;
        } else if (op == 'D') {
            int index;
            scanf("%d", &index);
            for (int j = index - 1; j < count - 1; j++)
                rectangles[j] = rectangles[j + 1];
            count--;
        } else if (op == 'Q') {
            Rectangle query;
            scanf("%d %d %d %d", &query.x1, &query.y1, &query.x2, &query.y2);
            int ans = 0;
            for (int j = 0; j < count; j++)
                if (intersect(&query, &rectangles[j]))
                    ans++;
            printf("%d\n", ans);
        }
    }
    free(rectangles);
    return 0;
}

