import java.util.Scanner;
public class Main {
    static class Rectangle {
        int x1, y1, x2, y2;
    }

    public static boolean intersect(Rectangle r1, Rectangle r2) {
        if (r1.x2 < r2.x1 || r2.x2 < r1.x1 || r1.y2 < r2.y1 || r2.y2 < r1.y1)
            return false;
        return true;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int Q = sc.nextInt();
        Rectangle[] rectangles = new Rectangle[Q];
        int count = 0;
        for (int i = 0; i < Q; i++) {
            char op = sc.next().charAt(0);
            if (op == 'I') {
                rectangles[count] = new Rectangle();
                rectangles[count].x1 = sc.nextInt();
                rectangles[count].y1 = sc.nextInt();
                rectangles[count].x2 = sc.nextInt();
                rectangles[count].y2 = sc.nextInt();
                count++;
            } else if (op == 'D') {
                int index = sc.nextInt();
                for (int j = index - 1; j < count - 1; j++)
                    rectangles[j] = rectangles[j + 1];
                count--;
            } else if (op == 'Q') {
                Rectangle query = new Rectangle();
                query.x1 = sc.nextInt();
                query.y1 = sc.nextInt();
                query.x2 = sc.nextInt();
                query.y2 = sc.nextInt();
                int ans = 0;
                for (int j = 0; j < count; j++)
                    if (intersect(query, rectangles[j]))
                        ans++;
                System.out.println(ans);
            }
        }
    }
}

