const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function intersect(r1, r2) {
    if (r1.x2 < r2.x1 || r2.x2 < r1.x1 || r1.y2 < r2.y1 || r2.y2 < r1.y1)
        return false;
    return true;
}

let Q = parseInt(lines[idx++]);
let rectangles = [];
for (let i = 0; i < Q; i++) {
    let op = lines[idx].split(' ')[0];
    if (op === 'I') {
        let [x1, y1, x2, y2] = lines[idx].split(' ').slice(1).map(Number);
        rectangles.push({ x1, y1, x2, y2 });
        idx++;
    } else if (op === 'D') {
        let index = parseInt(lines[idx].split(' ')[1]) - 1;
        rectangles.splice(index, 1);
        idx++;
    } else if (op === 'Q') {
        let [x1, y1, x2, y2] = lines[idx].split(' ').slice(1).map(Number);
        let query = { x1, y1, x2, y2 };
        let ans = rectangles.filter(r => intersect(query, r)).length;
        console.log(ans);
        idx++;
    }
}

